    assert grid[ly][rx] == 'B';
    assert 'B' in grid[ly];
    assert grid[ly][gcc] == 'B';
  }
  assert grid[ly][gcc] == 'B';

  // Compute center
  var y := (ly + ry) / 2;
  var x := (lx + rx) / 2;
  r := y + 1;
  c := x + 1;

