  assert y == gcr;
  assert lx + rx == 2 * gcc + 1;
  assert x == gcc;
  assert grid[ly][gcc] == 'B';
  assert grid[ly][gcc] == 'B';
  assert grid[ly][gcc] == 'B';
  assert grid[ly][gcc] == 'B';
  assert grid[ly][gcc] == 'B';
