      assert grid[ly][gcc + ghalf + 1] == 'B';
      assert 'B' in grid[ly];
    }
    rx := rx + 1;
  }
  if rx <= gcc + ghalf {
    assert grid[ly][gcc + ghalf] != 'B';
    assert grid[ly][gcc + ghalf + 1] == 'B';
    assert 'B' in grid[ly];
  }
  assert 'B' in grid[ly] && 'B' in grid[rx];

  // Compute center
  var y := (ly + ry) / 2;
  var x := (lx + rx) / 2;
  r := y + 1;
  c := x + 1;

  assert y == gcr;
  assert y == gcr;
  assert lx + rx == 2 * gcc + 1;
  assert x == gcc;
  assert x == gcc;
  assert lx + rx == 2 * gcc + 1;
  assert rx == gcc + ghalf + 1;
  assert grid[ly][rx] != 'B';
  assert grid[ly][gcc] == 'B';
  ProveExistsH(n, m, grid, r - 1, c - 1, ghalf);
}

